import { useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Navbar from "../../components/UI/Navbar";

// Tipo do retorno da API fake
interface FakeApiResponse {
  boletoLink: string;
  qrCode: string;
}

export default function PaymentPage() {
  const navigate = useNavigate();
  const location = useLocation();
  const { address } = location.state || {};

  const [paymentMethod, setPaymentMethod] = useState<string>("");
  const [error, setError] = useState<string>("");
  const [loading, setLoading] = useState<boolean>(false);
  const [pixQr, setPixQr] = useState<string>("");

  const subtotal = 200;
  const descontoPix = paymentMethod === "pix" ? subtotal * 0.05 : 0;
  const total = subtotal - descontoPix;

  // Campos do cartão com tipagem
  const [cardData, setCardData] = useState({
    name: "",
    number: "",
    exp: "",
    cvv: "",
  });

  // Máscaras com tipagem
  const maskCardNumber = (val: string) =>
    val
      .replace(/\D/g, "")
      .replace(/(\d{4})/g, "$1 ")
      .trim()
      .slice(0, 19);

  const maskExp = (val: string) =>
    val
      .replace(/\D/g, "")
      .replace(/(\d{2})(\d{0,2})/, "$1/$2")
      .slice(0, 5);

  const maskCVV = (val: string) => val.replace(/\D/g, "").slice(0, 3);

  const validate = () => {
    if (!paymentMethod) {
      setError("Escolha um método de pagamento.");
      return false;
    }

    if (paymentMethod === "card") {
      if (!cardData.name || !cardData.number || !cardData.exp || !cardData.cvv) {
        setError("Preencha todos os campos do cartão.");
        return false;
      }
    }

    setError("");
    return true;
  };

  // Tipagem da Promise aqui resolve o "unknown"
  const fakeApi = (): Promise<FakeApiResponse> =>
    new Promise((resolve) =>
      setTimeout(() => {
        resolve({
          boletoLink: "https://meubanco.com/boleto123.pdf",
          qrCode: "data:image/jpeg;base64,",
        });
      }, 1500)
    );

  const handleFinish = async () => {
    if (!validate()) return;

    setLoading(true);

    try {
      const response = await fakeApi(); // agora tem tipo certo

      if (paymentMethod === "boleto") {
        navigate("/checkout/boleto", {
          state: { link: response.boletoLink, total },
        });
      } else if (paymentMethod === "pix") {
        setPixQr(response.qrCode);
      } else {
        navigate("/checkout/success", {
          state: { address, paymentMethod, total },
        });
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <Navbar />

      {loading && (
        <div className="fixed inset-0 flex items-center justify-center bg-black/40 z-50">
          <div className="bg-white p-6 rounded-xl shadow-xl animate-pulse text-lg font-semibold">
            Processando pagamento...
          </div>
        </div>
      )}

      <div className="max-w-4xl mx-auto p-8">
        <h1 className="text-3xl font-bold text-black mb-6">
          Formas de Pagamento
        </h1>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {/* MÉTODOS */}
          <div className="col-span-1 space-y-4">
            {[
              { id: "card", label: "💳 Cartão de crédito" },
              { id: "boleto", label: "🧾 Boleto bancário" },
              { id: "pix", label: "⚡ Pix (5% de desconto)" },
            ].map((m) => (
              <button
                key={m.id}
                onClick={() => setPaymentMethod(m.id)}
                className={`w-full p-4 rounded-xl shadow-md border text-left transition 
                  hover:scale-[1.02] active:scale-[0.99]
                  ${
                    paymentMethod === m.id
                      ? "border-black bg-white"
                      : "bg-white/70"
                  }`}
              >
                {m.label}
              </button>
            ))}
          </div>

          {/* FORMULÁRIO */}
          <div className="col-span-2 bg-white rounded-2xl shadow-xl p-6 space-y-6">
            {error && (
              <div className="p-3 text-sm bg-red-100 border border-red-300 text-red-700 rounded-lg">
                {error}
              </div>
            )}

            {/* CARTÃO */}
            {paymentMethod === "card" && (
              <div className="space-y-4 animate-fadeIn">
                <h2 className="text-lg font-semibold">Informações do Cartão</h2>

                <input
                  type="text"
                  placeholder="Nome no cartão"
                  className="w-full p-3 border rounded-xl"
                  value={cardData.name}
                  onChange={(e) =>
                    setCardData({ ...cardData, name: e.target.value })
                  }
                />

                <input
                  type="text"
                  placeholder="Número do cartão"
                  className="w-full p-3 border rounded-xl"
                  value={cardData.number}
                  onChange={(e) =>
                    setCardData({
                      ...cardData,
                      number: maskCardNumber(e.target.value),
                    })
                  }
                />

                <div className="grid grid-cols-2 gap-4">
                  <input
                    type="text"
                    placeholder="Validade (MM/AA)"
                    className="p-3 border rounded-xl"
                    value={cardData.exp}
                    onChange={(e) =>
                      setCardData({ ...cardData, exp: maskExp(e.target.value) })
                    }
                  />

                  <input
                    type="text"
                    placeholder="CVV"
                    className="p-3 border rounded-xl"
                    value={cardData.cvv}
                    onChange={(e) =>
                      setCardData({
                        ...cardData,
                        cvv: maskCVV(e.target.value),
                      })
                    }
                  />
                </div>
              </div>
            )}

            {/* BOLETO */}
            {paymentMethod === "boleto" && (
              <p className="text-gray-600 animate-fadeIn">
                O boleto será gerado ao finalizar o pedido.
              </p>
            )}

            {/* PIX */}
            {paymentMethod === "pix" && (
              <div className="animate-fadeIn">
                <p className="text-gray-600">
                  Finalize para gerar o QR Code.
                </p>

                <p className="font-semibold text-green-600 mt-2">
                  Desconto: - R$ {(subtotal * 0.05).toFixed(2)}
                </p>

                {pixQr && (
                  <div className="mt-4">
                    <h3 className="font-semibold mb-2">Seu QR Code:</h3>
                    <img
                      src={pixQr}
                      alt="QR Code Pix"
                      className="w-48 h-48 border rounded-xl"
                    />
                  </div>
                )}
              </div>
            )}

            <div className="border-t pt-4">
              <div className="flex justify-between text-lg font-bold">
                <span>Total:</span>
                <span>R$ {total.toFixed(2)}</span>
              </div>
            </div>

            <button
              onClick={handleFinish}
              className="mt-4 w-full bg-black text-white py-3 rounded-xl font-semibold hover:bg-gray-900 transition"
            >
              Finalizar pedido
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}